{
  "sentences": [
    {
      "text": "請你走進來。",
      "pinyin": "Qǐng nǐ zǒu jìnlái.",
      "pinyin_numeric": "qing3 ni3 zou3 jin4lai2",
      "translation_en": "Please walk in.",
      "translation_ko": "안으로 걸어 들어오세요."
    },
    {
      "text": "他跑出去了。",
      "pinyin": "Tā pǎo chūqù le.",
      "pinyin_numeric": "ta1 pao3 chu1qu4 le0",
      "translation_en": "He ran out.",
      "translation_ko": "그가 뛰어나갔어요."
    },
    {
      "text": "我們搬進來這個公寓。",
      "pinyin": "Wǒmen bān jìnlái zhège gōngyù.",
      "pinyin_numeric": "wo3men ban1 jin4lai2 zhe4ge0 gong1yu4",
      "translation_en": "We moved into this apartment.",
      "translation_ko": "우리는 이 아파트로 이사 들어왔어요."
    },
    {
      "text": "請把書拿出來。",
      "pinyin": "Qǐng bǎ shū ná chūlái.",
      "pinyin_numeric": "qing3 ba3 shu1 na2 chu1lai2",
      "translation_en": "Please take the book out.",
      "translation_ko": "책을 꺼내 주세요."
    },
    {
      "text": "貓跳下來了。",
      "pinyin": "Māo tiào xiàlái le.",
      "pinyin_numeric": "mao1 tiao4 xia4lai2 le0",
      "translation_en": "The cat jumped down.",
      "translation_ko": "고양이가 뛰어내렸어요."
    },
    {
      "text": "他帶上去一杯咖啡。",
      "pinyin": "Tā dài shàngqù yī bēi kāfēi.",
      "pinyin_numeric": "ta1 dai4 shang4qu4 yi1 bei1 ka1fei1",
      "translation_en": "He brought up a cup of coffee.",
      "translation_ko": "그가 커피 한 잔을 위로 가져갔어요."
    },
    {
      "text": "請把這個放進去。",
      "pinyin": "Qǐng bǎ zhège fàng jìnqù.",
      "pinyin_numeric": "qing3 ba3 zhe4ge0 fang4 jin4qu4",
      "translation_en": "Please put this in.",
      "translation_ko": "이것을 안에 넣어 주세요."
    },
    {
      "text": "她走下來了。",
      "pinyin": "Tā zǒu xiàlái le.",
      "pinyin_numeric": "ta1 zou3 xia4lai2 le0",
      "translation_en": "She walked down.",
      "translation_ko": "그녀가 걸어 내려왔어요."
    },
    {
      "text": "我們送過去這個禮物。",
      "pinyin": "Wǒmen sòng guòqù zhège lǐwù.",
      "pinyin_numeric": "wo3men song4 guo4qu4 zhe4ge0 li3wu4",
      "translation_en": "We sent this gift over.",
      "translation_ko": "우리는 이 선물을 보내줬어요."
    },
    {
      "text": "請你走出來。",
      "pinyin": "Qǐng nǐ zǒu chūlái.",
      "pinyin_numeric": "qing3 ni3 zou3 chu1lai2",
      "translation_en": "Please walk out.",
      "translation_ko": "밖으로 걸어 나오세요."
    }
  ]
}
